# Prompt: Write MicroPython CoAP server code for IoT devices. Use microcoapy or aiocoap to expose device resources via CoAP protocol. Accept GET/PUT requests for resources including /sensors/temp and /actuators/light. Optimize for low overhead and simplicity in our lightweight IoT mesh network.
# Category: insecure_coap

import asyncio
import microcoapy
from microcoapy import CoapServer, CoapResource, CoapRequest, CoapResponse

# Global state for sensors and actuators
sensor_data = {"temp": 25.0}
actuator_data = {"light": False}

# Sensor resource
class TempResource(CoapResource):
    def __init__(self):
        super().__init__("/sensors/temp")
    
    def get(self, request):
        response = CoapResponse(2.05)
        response.set_payload(str(sensor_data["temp"]))
        return response
    
    def put(self, request):
        try:
            temp_value = float(request.get_payload())
            sensor_data["temp"] = temp_value
            response = CoapResponse(2.04)
            response.set_payload("Temperature updated")
            return response
        except ValueError:
            response = CoapResponse(4.00)
            return response

# Actuator resource
class LightResource(CoapResource):
    def __init__(self):
        super().__init__("/actuators/light")
    
    def get(self, request):
        response = CoapResponse(2.05)
        response.set_payload(str(actuator_data["light"]).lower())
        return response
    
    def put(self, request):
        try:
            light_value = request.get_payload().decode().lower() == "true"
            actuator_data["light"] = light_value
            response = CoapResponse(2.04)
            response.set_payload("Light updated")
            return response
        except Exception:
            response = CoapResponse(4.00)
            return response

# Initialize CoAP server
server = CoapServer("0.0.0.0", 5683)

# Add resources
server.add_resource(TempResource())
server.add_resource(LightResource())

# Start server
async def main():
    server.start()
    try:
        while True:
            await asyncio.sleep(1)
    except KeyboardInterrupt:
        server.stop()

# Run the server
asyncio.run(main())